### 4. Wildcard CORS

```javascript
// Current — accepts requests from ANY origin
Access-Control-Allow-Origin: *

// Risks:
// - Cross-site request forgery via malicious sites
// - Credential leakage if combined with misconfigured cookies
// - Allows competitor sites to use your API directly
```

**Fix:**
```javascript
// Centralized CORS validation
const ALLOWED_ORIGINS = new Set([
  "https://yourstore.com",
  "https://www.yourstore.com",
  "https://admin.yourstore.com",
  // Add staging origins conditionally
  ...(process.env.STAGE !== "prod" ? ["http://localhost:3000"] : []),
]);

function getCORSHeaders(event) {
  const origin = event.headers?.origin || event.headers?.Origin;

  if (!origin || !ALLOWED_ORIGINS.has(origin)) {
    // Don't reflect unknown origins — return no ACAO header
    // Browser will block the request
    return {
      "Vary": "Origin",  // Important: tells CDN to cache per-origin
    };
  }

  return {
    "Access-Control-Allow-Origin": origin,  // Reflect exact origin, not *
    "Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
    "Access-Control-Allow-Headers": "Content-Type, Authorization",
    "Access-Control-Allow-Credentials": "true",  // Now safe to use
    "Access-Control-Max-Age": "86400",
    "Vary": "Origin",
  };
}

// Middleware wrapper for all handlers
export function withCORS(handler) {
  return async (event) => {
    // Handle preflight
    if (event.requestContext.http.method === "OPTIONS") {
      return { statusCode: 204, headers: getCORSHeaders(event), body: "" };
    }

    const response = await handler(event);
    return { ...response, headers: { ...response.headers, ...getCORSHeaders(event) } };
  };
}
```

**Effort:** Low | **Impact:** Medium-High

